INSERT INTO quiz_question (id, word_bank_id, contextual_cloze, chinese_translation, correct_answer, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic) VALUES
('86878f5e-d6eb-5840-9ef1-ad295ea6bbc1', 'c4f5942a-678d-48f2-bbd4-e4002e5be424', 'The movie was so ___ that I watched it twice.', '這部電影非常有趣，以至於我看了兩次。', 'interesting', 'delicious', 'difficult', 'heavy', 'interest (興趣) + ing (形容詞字尾)', 'interest (興趣) + ing (令人...) → interesting (有趣的)'),
('aab416bb-61aa-5a0c-93ae-af3770d935bd', '30bf8c6c-a968-401c-a7c3-b2c1f53ae95d', 'This book is ___ the students who want to learn history.', '這本書是給想要學習歷史的學生看的。', 'for', 'to', 'with', 'by', '無字根 (表示對象或用途)', '針對特定對象時，使用 for'),
('c911a66c-f98d-5792-a654-d40ba952e18d', '24837458-0d4f-4a59-9dc7-ae944f0f278c', 'His dedication to social work ___ the reason why he is so respected.', '他對社會工作的奉獻是他受到如此尊重的理由。', 'is', 'has', 'does', 'says', 'be 動詞的第三人稱單數現在式', 'is 代表「是」或「在」，用於描述主詞的狀態或身分。');
